#include<bits/stdc++.h>
using namespace std;
char s[200010],t[200010],str[200010],temps[200010],tempt[200010];
int q;
bool f[20][20];
int main()
{
	memset(f,1,sizeof(f));
	scanf("%s%s",s+1,t+1);
	int len1=strlen(s+1),len2=strlen(t+1);
	for(int i=0;i<18;i++)
	{
		for(int j=0;j<18;j++)
		{
			int cnt1=0,cnt2=0;
			for(int k=0;k<len1;k++)
			{
				if(s[k]==i+'a'||s[k]==j+'a')
				{
					temps[++cnt1]=s[k];
				}
			}
			for(int k=0;k<len2;k++)
			{
				if(t[k]==i+'a'||t[k]==j+'a')
				{
					tempt[++cnt2]=t[k];
				}
			}
			if(cnt1!=cnt2)
			{
				f[i][j]=false;
				continue;
			}
			bool flag=true;
			for(int k=1;k<=cnt1;k++)
			{
				if(temps[k]!=tempt[k])
				{
					flag=false;
					break;
				}
			}
			if(flag)
			{
				f[i][j]=true;
			}
			else
			{
				f[i][j]=false;
			}
		}
	}
	scanf("%d",&q);
	while(q--)
	{
		scanf("%s",str+1);
		int n=strlen(str+1);
		bool flag=true;
		for(int i=1;i<=n;i++)
		{
			for(int j=1;j<=n;j++)
			{
				if(!f[str[i]-'a'][str[j]-'a'])
				{
					flag=false;
					break;
				}
			}
			if(!flag)
			{
				break;
			}
		}
		if(flag)
		{
			printf("Y");
		}
		else
		{
			printf("N");
		}
	}
	return 0;
}
